1	import { create } from 'zustand';
2	import { persist } from 'zustand/middleware';
3	import type { CanvasNode, CanvasNodeType } from '@/shared/types';
4	import { 
5	  createCanvasNode, 
6	  getCanvasNodesByProject, 
7	  updateCanvasNode, 
8	  deleteCanvasNode,
9	  updateCanvasNodePosition 
10	} from '@/shared/lib/supabase/services/canvasNodes';
11	import { getClientForEnvironment } from '@/shared/utils/authenticatedClient';
12	
13	interface CanvasNodesState {
14	  // State
15	  canvasNodes: CanvasNode[];
16	  isLoading: boolean;
17	  error: string | undefined;
18	
19	  // Actions
20	  loadCanvasNodes: (projectId: string) => Promise<void>;
21	  createNode: (nodeData: Omit<CanvasNode, 'id' | 'createdAt' | 'updatedAt'>) => Promise<CanvasNode>;
22	  updateNode: (nodeId: string, updates: Partial<Pick<CanvasNode, 'title' | 'position' | 'data'>>) => Promise<void>;
23	  updateNodePosition: (nodeId: string, position: { x: number; y: number }) => Promise<void>;
24	  deleteNode: (nodeId: string) => Promise<void>;
25	  
26	  // Local state management
27	  addNodeLocal: (node: CanvasNode) => void;
28	  updateNodeLocal: (nodeId: string, updates: Partial<CanvasNode>) => void;
29	  removeNodeLocal: (nodeId: string) => void;
30	  clearNodes: () => void;
31	  
32	  // Utilities
33	  getNodeById: (nodeId: string) => CanvasNode | undefined;
34	  getNodesByType: (nodeType: CanvasNodeType) => CanvasNode[];
35	}
36	
37	export const useCanvasNodesStore = create<CanvasNodesState>()(
38	  persist(
39	    (set, get) => ({
40	      // Initial state
41	      canvasNodes: [],
42	      isLoading: false,
43	      error: undefined,
44	
45	      // Load canvas nodes for a project
46	      loadCanvasNodes: async (projectId: string) => {
47	        set({ isLoading: true, error: undefined });
48	        
49	        try {
50	          const client = getClientForEnvironment();
51	          const nodes = await getCanvasNodesByProject(projectId, client);
52	          
53	          set({ 
54	            canvasNodes: nodes, 
55	            isLoading: false 
56	          });
57	          
58	          console.log(`✅ Loaded ${nodes.length} canvas nodes for project ${projectId}`);
59	        } catch (error) {
60	          console.error('❌ Error loading canvas nodes:', error);
61	          set({ 
62	            error: error instanceof Error ? error.message : 'Failed to load canvas nodes',
63	            isLoading: false 
64	          });
65	        }
66	      },
67	
68	      // Create a new canvas node
69	      createNode: async (nodeData) => {
70	        set({ isLoading: true, error: undefined });
71	        
72	        try {
73	          const client = getClientForEnvironment();
74	          const newNode = await createCanvasNode(nodeData, client);
75	          
76	          // Add to local state
77	          set(state => ({
78	            canvasNodes: [...state.canvasNodes, newNode],
79	            isLoading: false
80	          }));
81	          
82	          console.log(`✅ Created canvas node: ${newNode.id} (${newNode.nodeType})`);
83	          return newNode;
84	        } catch (error) {
85	          console.error('❌ Error creating canvas node:', error);
86	          set({ 
87	            error: error instanceof Error ? error.message : 'Failed to create canvas node',
88	            isLoading: false 
89	          });
90	          throw error;
91	        }
92	      },
93	
94	      // Update a canvas node
95	      updateNode: async (nodeId, updates) => {
96	        try {
97	          const client = getClientForEnvironment();
98	          const updatedNode = await updateCanvasNode(nodeId, updates, client);
99	          
100	          // Update local state
101	          set(state => ({
102	            canvasNodes: state.canvasNodes.map(node =>
103	              node.id === nodeId ? updatedNode : node
104	            )
105	          }));
106	          
107	          console.log(`✅ Updated canvas node: ${nodeId}`);
108	        } catch (error) {
109	          console.error('❌ Error updating canvas node:', error);
110	          set({ error: error instanceof Error ? error.message : 'Failed to update canvas node' });
111	          throw error;
112	        }
113	      },
114	
115	      // Update canvas node position (optimized for frequent updates)
116	      updateNodePosition: async (nodeId, position) => {
117	        // Update local state immediately for smooth UX
118	        set(state => ({
119	          canvasNodes: state.canvasNodes.map(node =>
120	            node.id === nodeId 
121	              ? { ...node, position, updatedAt: new Date().toISOString() }
122	              : node
123	          )
124	        }));
125	
126	        try {
127	          const client = getClientForEnvironment();
128	          await updateCanvasNodePosition(nodeId, position, client);
129	          console.log(`✅ Updated canvas node position: ${nodeId}`);
130	        } catch (error) {
131	          console.error('❌ Error updating canvas node position:', error);
132	          // Revert local state on error
133	          set(state => ({
134	            canvasNodes: state.canvasNodes.map(node =>
135	              node.id === nodeId 
136	                ? { ...node, position: node.position } // Revert to original position
137	                : node
138	            ),
139	            error: error instanceof Error ? error.message : 'Failed to update node position'
140	          }));
141	        }
142	      },
143	
144	      // Delete a canvas node
145	      deleteNode: async (nodeId) => {
146	        try {
147	          const client = getClientForEnvironment();
148	          await deleteCanvasNode(nodeId, client);
149	          
150	          // Remove from local state
151	          set(state => ({
152	            canvasNodes: state.canvasNodes.filter(node => node.id !== nodeId)
153	          }));
154	          
155	          console.log(`✅ Deleted canvas node: ${nodeId}`);
156	        } catch (error) {
157	          console.error('❌ Error deleting canvas node:', error);
158	          set({ error: error instanceof Error ? error.message : 'Failed to delete canvas node' });
159	          throw error;
160	        }
161	      },
162	
163	      // Local state management
164	      addNodeLocal: (node) => {
